import{c as o,Q as a,j as t,m as n}from"./chunks/framework.CdiUUa3G.js";const g=JSON.parse('{"title":"ADR-048 — Tiangong Explorer asset pipeline and nav placement","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-048.md","filePath":"adr/ADR-048.md"}'),r={name:"adr/ADR-048.md"};function i(s,e,d,l,c,p){return a(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="adr-048-—-tiangong-explorer-asset-pipeline-and-nav-placement" tabindex="-1">ADR-048 — Tiangong Explorer asset pipeline and nav placement <a class="header-anchor" href="#adr-048-—-tiangong-explorer-asset-pipeline-and-nav-placement" aria-label="Permalink to &quot;ADR-048 — Tiangong Explorer asset pipeline and nav placement&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-05-07 Closes · RFC-014 (with ADR-049, ADR-050) TA anchor · §components / primary-route-pages Related · PRD-011, ADR-040 (the ISS analogue), ADR-016 (build-time assets), ADR-017 (i18n), ADR-046 / ADR-047 (provenance)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>PRD-011 / GitHub #50 introduce <code>/tiangong</code>: a rotatable Tiangong with per-module panels mirroring the <code>/iss</code> playbook. RFC-014 OQ-1, OQ-4, OQ-7 asked where the mesh comes from, what the Earth backdrop is, and where Tiangong sits in nav.</p><p>The wrinkle vs RFC-013: <strong>NASA-3D Resources is unavailable</strong> for Tiangong. The Wolf Amendment legally prohibits NASA cooperation with Chinese space programmes, so no NASA-authored Tiangong models exist. Asset sourcing for any future GLB swap is harder, not easier, than ISS.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="model-source-rfc-oq-1-—-option-a" tabindex="-1">Model source (RFC OQ-1 — Option A) <a class="header-anchor" href="#model-source-rfc-oq-1-—-option-a" aria-label="Permalink to &quot;Model source (RFC OQ-1 — Option A)&quot;">​</a></h3><p><strong>V1 ships a code-built diagrammatic Tiangong</strong> in <a href="../../src/lib/tiangong-proxy-model.ts"><code>src/lib/tiangong-proxy-model.ts</code></a>: Three.js cylinder + box primitives assembled at runtime so each canonical module id from <a href="../../static/data/tiangong-modules.json"><code>tiangong-modules.json</code></a> maps to a named pickable mesh (<code>userData.moduleId</code>). Identical pattern to ADR-040. <strong>No Node-side GLTF export</strong> (same constraint as ISS).</p><p><strong>Rationale:</strong> The code-built proxy ships immediately, is MIT-licensed, has zero asset-sourcing risk, and renders the recognisable T-shape silhouette in ~2,000 tris (3 module cylinders + 8 solar wings + 5-segment Chinarm + 2 visiting vehicles). A future GLB swap (RFC-014 OQ-1 options B/C/D) is deferred to V1.5/V2 once the credits-rollout pipeline (ADR-046 / ADR-047) has matured for Chinese-state imagery + model provenance.</p><p><strong>Budget:</strong> Proxy stays <strong>≪ 50k tris</strong> (low thousands). A future CMSA / Sketchfab / Blender-authored GLB must stay within PRD <strong>~50k tris</strong> and <strong>&lt; 4 MB</strong> gzipped.</p><h3 id="earth-limb-backdrop-rfc-oq-4-—-option-b" tabindex="-1">Earth limb backdrop (RFC OQ-4 — Option B) <a class="header-anchor" href="#earth-limb-backdrop-rfc-oq-4-—-option-b" aria-label="Permalink to &quot;Earth limb backdrop (RFC OQ-4 — Option B)&quot;">​</a></h3><p>Static <strong>Earth limb</strong> behind the station using existing texture <a href="../../static/textures/2k_earth_daymap.jpg"><code>static/textures/2k_earth_daymap.jpg</code></a> (same asset as <code>/iss</code> + <code>/earth</code> + <code>/explore</code>): large textured sphere, no animated rotation in V1.</p><h3 id="nav-order-rfc-oq-7" tabindex="-1">Nav order (RFC OQ-7) <a class="header-anchor" href="#nav-order-rfc-oq-7" aria-label="Permalink to &quot;Nav order (RFC OQ-7)&quot;">​</a></h3><p>Insert <strong>TIANGONG</strong> after <strong>ISS</strong>, grouping the LEO crewed-habitat cluster:</p><p><code>EXPLORE → MISSIONS → PLAN → FLY → EARTH → ISS → TIANGONG → MOON → MARS</code></p><h3 id="earth-object-panel-migration" tabindex="-1">Earth-object panel migration <a class="header-anchor" href="#earth-object-panel-migration" aria-label="Permalink to &quot;Earth-object panel migration&quot;">​</a></h3><p>Tiangong currently lives as a 3-photo <code>EARTH_OBJECT_QUERIES</code> panel (<code>static/images/earth-objects/tiangong/</code>). On <code>/tiangong</code> ship the earth-object entry is removed and the asset folder deleted; gallery imagery moves under the station-modules pipeline (see ADR-049 + Phase G of the rollout plan).</p><h3 id="build-hook" tabindex="-1">Build hook <a class="header-anchor" href="#build-hook" aria-label="Permalink to &quot;Build hook&quot;">​</a></h3><p><code>npm run build</code> does not invoke Blender or mesh exporters. Adjust layout in <code>tiangong-proxy-model.ts</code> when module positions change.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p><strong>Positive:</strong> Predictable CI; no Wolf-Amendment-tangled asset checkout in V1; ships fast; clear path to swap to a vetted GLB once provenance work matures.</p><p><strong>Negative:</strong> V1 silhouette is <strong>diagrammatic</strong>, not photoreal — acceptable for interaction proof; PRD &quot;recognisable Tiangong&quot; is met via the iconic T-layout and labelling, not film-grade mesh.</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li>Proxy builder lives in <code>src/lib/tiangong-proxy-model.ts</code>; shared station helpers (<code>setShadowFlags</code>, <code>cylinderBetween</code>, <code>makeWingPair</code>) in <code>src/lib/station-geometry.ts</code> (extracted from <code>iss-proxy-model.ts</code>).</li><li>Future GLB swap path: a separate RFC will revisit OQ-1 options B/C/D once <code>static/data/image-provenance.json</code> workflow has shipped a Chinese-source case.</li></ul>',24)])])}const m=o(r,[["render",i]]);export{g as __pageData,m as default};
